function ensurePackageJson() {
  if (!exists(packageJsonPath)) {
    console.error("Error: package.json not found in current directory.");
    process.exit(1);
  }
}

function generateLockFile() {
  ensurePackageJson();
  if (exists(lockFilePath)) {
    console.log("package-lock.json already exists.");
  } else {
    console.log("Generating package-lock.json...");
  }
  run("npm install --package-lock-only");
}

function ciInstall() {
  ensurePackageJson();
  if (!exists(lockFilePath)) {
    console.error("Error: package-lock.json is required for npm ci.");
    process.exit(1);
  }
  run("npm ci");
}

function updateDeps() {
  ensurePackageJson();
  if (!exists(lockFilePath)) {
    console.log("No package-lock.json found. Generating one first...");
    run("npm install --package-lock-only");
  }
  run("npm update");
}

function validate() {
  ensurePackageJson();

  if (!exists(lockFilePath)) {
    console.error("Validation failed: package-lock.json does not exist.");
    process.exit(1);
  }

  const pkg = readJson(packageJsonPath);
  const lock = readJson(lockFilePath);

  if (!pkg.name) {
    console.warn("Warning: package.json has no 'name' field.");
  }

  if (!lock.lockfileVersion) {
    console.warn("Warning: package-lock.json has no lockfileVersion.");
  } else {
    console.log(`Detected lockfileVersion: ${lock.lockfileVersion}`);
  }

  try {
    run("npm ci --ignore-scripts");
    console.log("\nValidation passed: package-lock.json is present and npm ci succeeded.");
  } catch (err) {
    console.error("\nValidation failed: npm ci did not succeed.");
    process.exit(1);
  }
}

const arg = process.argv[2];

switch (arg) {
  case "--generate":
    generateLockFile();
    break;
  case "--ci":
    ciInstall();
    break;
  case "--update":
    updateDeps();
    break;
  case "--validate":
    validate();
    break;
  case "--help":
  case undefined:
    printHelp();
    break;
  default:
    console.error(`Unknown option: ${arg}`);
    printHelp();
    process.exit(1);
}